function debounce(func, wait) {
    return function() {
        let context, args;
        clearTimeout(timeout);
        timeout = setTimeout(function() {
            func.apply(context, args);
        }, wait);
    };
}

let timeout;
function myFunction() {
    console.log('Function called');
}

let debouncedMyFunction = debounce(myFunction, 500);

// Example usage
setTimeout(() => {
    debouncedMyFunction();  // Function won't be called immediately on this click
}, 100);
setTimeout(() => {
    debouncedMyFunction();  // Function won't be called immediately on this click, too
}, 150);
setTimeout(() => {
    debouncedMyFunction();  // Function will be called 500ms after this click
}, 700);
